2275 /// Attempt to fold an SSE floating point to integer conversion of a constant
2276 /// floating point. If roundTowardZero is false, the default IEEE rounding is
2277 /// used (toward nearest, ties to even). This matches the behavior of the
2278 /// non-truncating SSE instructions in the default rounding mode. The desired
2279 /// integer type Ty is used to select how many bits are available for the
2280 /// result. Returns null if the conversion cannot be performed, otherwise
2281 /// returns the Constant value resulting from the conversion.
2282 Constant *ConstantFoldSSEConvertToInt(const APFloat &Val, bool roundTowardZero,
2283                                       Type *Ty, bool IsSigned) {
2284   // All of these conversion intrinsics form an integer of at most 64bits.
2285   unsigned ResultWidth = Ty->getIntegerBitWidth();
2286   assert(ResultWidth <= 64 &&
2287          "Can only constant fold conversions to 64 and 32 bit ints");
