2294       Val.convertToInteger(MutableArrayRef(UIntVal), ResultWidth,
2295                            IsSigned, mode, &isExact);
2296   if (status != APFloat::opOK &&
2297       (!roundTowardZero || status != APFloat::opInexact))
2298     return nullptr;
