2326 /// Checks if the given intrinsic call, which evaluates to constant, is allowed
2327 /// to be folded.
2328 ///
2329 /// \param CI Constrained intrinsic call.
2330 /// \param St Exception flags raised during constant evaluation.
2331 static bool mayFoldConstrained(ConstrainedFPIntrinsic *CI,
2332                                APFloat::opStatus St) {
2333   std::optional<RoundingMode> ORM = CI->getRoundingMode();
2334   std::optional<fp::ExceptionBehavior> EB = CI->getExceptionBehavior();
2335 
2336   // If the operation does not change exception status flags, it is safe
2337   // to fold.
2338   if (St == APFloat::opStatus::opOK)
2339     return true;
2340 
2341   // If evaluation raised FP exception, the result can depend on rounding
2342   // mode. If the latter is unknown, folding is not possible.
2343   if (ORM == RoundingMode::Dynamic)
2344     return false;
2345 
2346   // If FP exceptions are ignored, fold the call, even if such exception is
2347   // raised.
2348   if (EB && *EB != fp::ExceptionBehavior::ebStrict)
2349     return true;
2350 
2351   // Leave the calculation for runtime so that exception flags be correctly set
2352   // in hardware.
2353   return false;
2354 }
