2356 /// Returns the rounding mode that should be used for constant evaluation.
2357 static RoundingMode
2358 getEvaluationRoundingMode(const ConstrainedFPIntrinsic *CI) {
2359   std::optional<RoundingMode> ORM = CI->getRoundingMode();
2360   if (!ORM || *ORM == RoundingMode::Dynamic)
2361     // Even if the rounding mode is unknown, try evaluating the operation.
2362     // If it does not raise inexact exception, rounding was not applied,
2363     // so the result is exact and does not depend on rounding mode. Whether
2364     // other FP exceptions are raised, it does not depend on rounding mode.
2365     return RoundingMode::NearestTiesToEven;
2366   return *ORM;
2367 }
