2369 /// Try to constant fold llvm.canonicalize for the given caller and value.
2370 static Constant *constantFoldCanonicalize(const Type *Ty, const CallBase *CI,
2371                                           const APFloat &Src) {
2372   // Zero, positive and negative, is always OK to fold.
2373   if (Src.isZero()) {
2374     // Get a fresh 0, since ppc_fp128 does have non-canonical zeros.
2375     return ConstantFP::get(
