2382 
2383   // Zero is always canonical and the sign must be preserved.
2384   //
2385   // Denorms and nans may have special encodings, but it should be OK to fold a
2386   // totally average number.
2387   if (Src.isNormal() || Src.isInfinity())
2388     return ConstantFP::get(CI->getContext(), Src);
2389 
2390   if (Src.isDenormal() && CI->getParent() && CI->getFunction()) {
2391     DenormalMode DenormMode =
2392         CI->getFunction()->getDenormalMode(Src.getSemantics());
2393 
2394     if (DenormMode == DenormalMode::getIEEE())
2395       return ConstantFP::get(CI->getContext(), Src);
2396 
2397     if (DenormMode.Input == DenormalMode::Dynamic)
