2399 
2400     // If we know if either input or output is flushed, we can fold.
2401     if ((DenormMode.Input == DenormalMode::Dynamic &&
2402          DenormMode.Output == DenormalMode::IEEE) ||
2403         (DenormMode.Input == DenormalMode::IEEE &&
2404          DenormMode.Output == DenormalMode::Dynamic))
2405       return nullptr;
2406 
2407     bool IsPositive =
2408         (!Src.isNegative() || DenormMode.Input == DenormalMode::PositiveZero ||
2409          (DenormMode.Output == DenormalMode::PositiveZero &&
2410           DenormMode.Input == DenormalMode::IEEE));
2411 
2412     return ConstantFP::get(CI->getContext(),
2413                            APFloat::getZero(Src.getSemantics(), !IsPositive));
2414   }
2415 
2416   return nullptr;
2417 }
